function TF({label,k,value,onChange,type="text",options=null,placeholder=""}) {
  const s={background:C.bg,border:`1px solid ${C.border}`,borderRadius:8,padding:"8px 11px",color:C.ink,fontFamily:"Arial,sans-serif",fontSize:13,outline:"none",width:"100%",colorScheme:"light"};
  return <div style={{display:"flex",flexDirection:"column",gap:4}}>
    <label style={{fontSize:10,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>{label}</label>
    {options?<select value={value} onChange={e=>onChange(k,e.target.value)} style={{...s,color:value?C.ink:C.muted}}><option value="">Select…</option>{options.map(o=><option key={o.v||o} value={o.v||o}>{o.l||o}</option>)}</select>
    :<input type={type} value={value} onChange={e=>onChange(k,e.target.value)} placeholder={placeholder} style={s}/>}
  </div>;
}

// ── TASK BOARD ────────────────────────────────────────────────────────────────
function TaskBoard({tasks,users,onAdd,onUpdate,onDelete}) {
  const [showForm,setShowForm]=useState(false);
  const [editing,setEditing]=useState(null);
  const [form,setForm]=useState({task:"",owner:"",priority:"Medium",status:"Not Started",due_date:"",notes:""});
  const [done,setDone]=useState(false);
  const [filterOwner,setFilterOwner]=useState("");
  const [filterStatus,setFilterStatus]=useState("");

  function setF(k,v){setForm(f=>({...f,[k]:v}));}
  function openAdd(){setEditing(null);setForm({task:"",owner:"",priority:"Medium",status:"Not Started",due_date:"",notes:""});setShowForm(true);}
  function openEdit(t){setEditing(t);setForm({task:t.task,owner:t.owner,priority:t.priority,status:t.status,due_date:t.due_date||"",notes:t.notes||""});setShowForm(true);}
  function cancelForm(){setShowForm(false);setEditing(null);}
  async function save(){
    if(!form.task.trim()){alert("Task required.");return;}
    if(!form.owner){alert("Owner required.");return;}
    editing?await onUpdate(editing.id,form):await onAdd(form);
    setDone(true);setTimeout(()=>{setDone(false);cancelForm();},900);
  }
  function cycleStatus(t){onUpdate(t.id,{status:TASK_STATUSES[(TASK_STATUSES.indexOf(t.status)+1)%TASK_STATUSES.length]});}

  const userOpts=users.filter(u=>u.active).map(u=>({v:u.name,l:u.name}));
  const filtered=tasks.filter(t=>(!filterOwner||t.owner===filterOwner)&&(!filterStatus||t.status===filterStatus))
    .sort((a,b)=>{if(a.status==="Done"&&b.status!=="Done")return 1;if(b.status==="Done"&&a.status!=="Done")return -1;return ({"High":0,"Medium":1,"Low":2}[a.priority]||1)-({"High":0,"Medium":1,"Low":2}[b.priority]||1);});
  const overdue=tasks.filter(t=>t.status!=="Done"&&t.due_date&&daysUntil(t.due_date)<0);
  const dueToday=tasks.filter(t=>t.status!=="Done"&&t.due_date&&daysUntil(t.due_date)===0);

  return <div style={{display:"flex",flexDirection:"column",gap:14}}>
    {showForm&&<Card style={{padding:20,border:`1px solid ${C.blue}44`}}>
      <div style={{fontSize:18,fontWeight:700,color:C.ink,marginBottom:16}}>{editing?"Edit Task":"New Task"}</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:12,marginBottom:14}}>
        <div style={{gridColumn:"span 4"}}><TF label="Task Description *" k="task" value={form.task} onChange={setF} placeholder="e.g. Send quotation to BASF Nutrition"/></div>
        <TF label="Owner *" k="owner" value={form.owner} onChange={setF} options={userOpts}/>
        <TF label="Priority" k="priority" value={form.priority} onChange={setF} options={["High","Medium","Low"]}/>
        <TF label="Due Date" k="due_date" value={form.due_date} onChange={setF} type="date"/>
        <TF label="Status" k="status" value={form.status} onChange={setF} options={TASK_STATUSES}/>
        <div style={{gridColumn:"span 4"}}><TF label="Notes" k="notes" value={form.notes} onChange={setF} placeholder="Optional notes…"/></div>
      </div>
      <div style={{display:"flex",gap:10}}>
        <Btn label={done?"✓ Saved!":editing?"Update Task":"Add Task"} onClick={save} disabled={done}/>
        <Btn label="Cancel" onClick={cancelForm} variant="ghost"/>
      </div>
    </Card>}
    <Card style={{overflow:"hidden"}}>
      <div style={{padding:"13px 18px",display:"flex",gap:10,alignItems:"center",borderBottom:`1px solid ${C.border}`,flexWrap:"wrap"}}>
        <div style={{fontSize:18,fontWeight:700,color:C.ink}}>Tasks <span style={{fontSize:12,color:C.blue,fontWeight:400}}>{tasks.filter(t=>t.status!=="Done").length} open</span></div>
        {!showForm&&<Btn label="+ New Task" onClick={openAdd} size="sm"/>}
        <select value={filterOwner} onChange={e=>setFilterOwner(e.target.value)} style={{marginLeft:"auto",background:C.white,border:`1px solid ${C.border}`,borderRadius:7,padding:"6px 10px",color:C.ink,fontSize:11}}>
          <option value="">All Team</option>
          {users.filter(u=>u.active).map(u=><option key={u.id} value={u.name}>{u.name.split(" ")[0]}</option>)}
        </select>
        <select value={filterStatus} onChange={e=>setFilterStatus(e.target.value)} style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:7,padding:"6px 10px",color:C.ink,fontSize:11}}>
          <option value="">All Status</option>
          {TASK_STATUSES.map(s=><option key={s} value={s}>{s}</option>)}
        </select>
      </div>
      {(overdue.length>0||dueToday.length>0)&&<div style={{padding:"8px 18px",background:"#FFF0F0",borderBottom:`1px solid #FFDAD9`,display:"flex",gap:14}}>
        {overdue.length>0&&<span style={{fontSize:11,color:C.red,fontWeight:700}}>⚠ {overdue.length} task{overdue.length>1?"s":""} overdue</span>}
        {dueToday.length>0&&<span style={{fontSize:11,color:C.amber,fontWeight:700}}>⚡ {dueToday.length} due today</span>}
      </div>}
      {filtered.length===0
        ?<div style={{padding:30,textAlign:"center",color:C.muted,fontSize:12}}>No tasks — click + New Task to add one</div>
        :filtered.map((t,i)=>{
          const d=daysUntil(t.due_date);
          const isOver=t.status!=="Done"&&t.due_date&&d<0;
          const isToday=t.status!=="Done"&&t.due_date&&d===0;
          const isDone=t.status==="Done";
          const sc=TASK_STATUS_COLORS[t.status]||C.muted;
          const pc=PRIO_COLORS[t.priority]||C.muted;
          return <div key={t.id} style={{display:"flex",alignItems:"center",gap:11,padding:"10px 18px",background:i%2===0?C.bg:"transparent",borderBottom:`1px solid ${C.border}`}}>
            <div onClick={()=>cycleStatus(t)} style={{width:13,height:13,borderRadius:"50%",background:sc,flexShrink:0,cursor:"pointer"}}/>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:12,color:isDone?C.faded:C.ink,fontWeight:isDone?400:600,textDecoration:isDone?"line-through":"none",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.task}</div>
              {t.notes&&<div style={{fontSize:11,color:C.muted,marginTop:1}}>{t.notes}</div>}
            </div>
            <span style={{fontSize:11,color:C.muted,minWidth:50,textAlign:"right"}}>{(t.owner||"").split(" ")[0]}</span>
            <span style={{background:`${pc}22`,color:pc,border:`1px solid ${pc}44`,borderRadius:20,padding:"2px 9px",fontSize:10,fontWeight:700}}>{t.priority}</span>
            <span style={{background:`${sc}22`,color:sc,border:`1px solid ${sc}44`,borderRadius:20,padding:"2px 9px",fontSize:10,fontWeight:700,minWidth:88,textAlign:"center"}}>{t.status}</span>
            <span style={{fontSize:11,color:isOver?C.red:isToday?C.amber:C.muted,fontWeight:isOver||isToday?700:400,minWidth:86,textAlign:"right"}}>
              {t.due_date?(isOver?`⚠ ${Math.abs(d)}d ago`:isToday?"⚡ Today":fmtDate(t.due_date)):"—"}
            </span>
            <button onClick={()=>openEdit(t)} style={{background:"transparent",border:`1px solid ${C.border}`,borderRadius:6,padding:"3px 9px",cursor:"pointer",color:C.blue,fontSize:10}}>Edit</button>
            <button onClick={()=>onDelete(t.id)} style={{background:"transparent",border:`1px solid ${C.red}44`,borderRadius:6,padding:"3px 7px",cursor:"pointer",color:C.red,fontSize:10}}>✕</button>
          </div>;
        })
      }
    </Card>
  </div>;
}

// ── QUOTATION TAB ─────────────────────────────────────────────────────────────
function QuotationTab({enq,quotations,onSave,onSendEmail,users}) {
  const enqQuots=quotations.filter(q=>q.enquiry_id===enq.id).sort((a,b)=>b.version-a.version);
  const latest=enqQuots[0];
  const [form,setForm]=useState(()=>latest?{
    validity_days:latest.validity_days||30,paymentTerms:latest.payment_terms||"",
    incoterms:latest.incoterms||"CIF",notes:latest.notes||"",
    items:Array.isArray(latest.items)?latest.items:[],
  }:{validity_days:30,paymentTerms:"",incoterms:"CIF",notes:"",
    items:(Array.isArray(enq.products)?enq.products:[]).map(p=>({name:p.name,qty:p.qty||"",unit:p.unit||"kg",unitPrice:"",totalPrice:""}))});
  const [saving,setSaving]=useState(false);
  const [sending,setSending]=useState(false);
  const [sent,setSent]=useState(false);
  const [showHistory,setShowHistory]=useState(false);

  function setF(k,v){setForm(f=>({...f,[k]:v}));}
  function setItem(i,field,val){
    setForm(f=>{
      const items=f.items.map((it,idx)=>{
        if(idx!==i)return it;
        const u={...it,[field]:val};
        if(field==="qty"||field==="unitPrice"){
          const q=parseFloat(field==="qty"?val:u.qty)||0;
          const p=parseFloat(field==="unitPrice"?val:u.unitPrice)||0;
          u.totalPrice=q&&p?(q*p).toFixed(2):"";
        }
        return u;
      });
      return {...f,items};
    });
  }
  function addItem(){setForm(f=>({...f,items:[...f.items,{name:"",qty:"",unit:"kg",unitPrice:"",totalPrice:""}]}));}
  function removeItem(i){setForm(f=>({...f,items:f.items.filter((_,idx)=>idx!==i)}));}

  const grandTotal=form.items.reduce((s,it)=>s+(parseFloat(it.totalPrice)||0),0);

  async function handleSave(){
    if(!form.items.length||!form.items[0].name){alert("Add at least one product.");return;}
    setSaving(true);
    const newVer=(latest?.version||0)+1;
    await onSave({enquiry_id:enq.id,customer_name:enq.customer_name,version:newVer,items:form.items,grand_total:grandTotal,currency:enq.currency||"USD",validity_days:form.validity_days,payment_terms:form.paymentTerms,incoterms:form.incoterms,notes:form.notes,status:"Draft"});
    setSaving(false);
  }

  async function handleSend(){
    setSending(true);
    await onSendEmail(enq,form,grandTotal,users);
    setSent(true);setTimeout(()=>setSent(false),3000);setSending(false);
  }

  const inp={background:C.bg,border:`1px solid ${C.border}`,borderRadius:7,padding:"7px 10px",color:C.ink,fontFamily:"Arial,sans-serif",fontSize:12,outline:"none",width:"100%"};

  return <div style={{padding:"16px 0"}}>
    {enqQuots.length>0&&<div style={{marginBottom:14}}>
      <button onClick={()=>setShowHistory(!showHistory)} style={{background:C.blueLt,border:`1px solid #BFD6F6`,borderRadius:7,padding:"5px 12px",cursor:"pointer",color:C.blue,fontSize:11,fontWeight:700}}>
        {showHistory?"▲ Hide":"▼ Show"} Version History ({enqQuots.length})
      </button>
      {showHistory&&<div style={{marginTop:10,display:"flex",flexDirection:"column",gap:6}}>
        {enqQuots.map(q=><div key={q.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:C.bg,borderRadius:8,padding:"8px 12px",border:`1px solid ${C.border}`}}>
          <div>
            <span style={{fontSize:12,fontWeight:700,color:C.ink}}>v{q.version}</span>
            <span style={{fontSize:11,color:C.muted,marginLeft:8}}>{fmtDate(q.created_at)}</span>
            <span style={{fontSize:11,color:C.muted,marginLeft:8}}>{q.currency} {Number(q.grand_total||0).toLocaleString()}</span>
          </div>
          <span style={{background:q.status==="Sent"?"#E6F4EA":C.bg,color:q.status==="Sent"?C.green:C.muted,border:`1px solid ${q.status==="Sent"?"#C3E6CB":C.border}`,borderRadius:20,padding:"2px 9px",fontSize:10,fontWeight:700}}>{q.status}</span>
        </div>)}
      </div>}
    </div>}
    <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.blue,textTransform:"uppercase",marginBottom:12}}>
      {latest?`v${(latest.version||0)+1} — Edit Quotation`:"Create Quotation"}
    </div>
    <div style={{marginBottom:14}}>
      <div style={{display:"grid",gridTemplateColumns:"1fr 80px 70px 90px 90px 28px",gap:6,marginBottom:6}}>
        {["Product","Qty","Unit","Unit Price","Total",""].map((h,i)=><div key={i} style={{fontSize:9,fontWeight:700,letterSpacing:1,color:C.muted,textTransform:"uppercase"}}>{h}</div>)}
      </div>
      {form.items.map((it,i)=><div key={i} style={{display:"grid",gridTemplateColumns:"1fr 80px 70px 90px 90px 28px",gap:6,marginBottom:6,alignItems:"center"}}>
        <input value={it.name} onChange={e=>setItem(i,"name",e.target.value)} placeholder="Product name" style={inp}/>
        <input value={it.qty} onChange={e=>setItem(i,"qty",e.target.value)} placeholder="500" style={inp}/>
        <select value={it.unit} onChange={e=>setItem(i,"unit",e.target.value)} style={{...inp,padding:"7px 4px"}}>
          {UNITS.map(u=><option key={u} value={u}>{u}</option>)}
        </select>
        <input value={it.unitPrice} onChange={e=>setItem(i,"unitPrice",e.target.value)} placeholder="0.00" style={inp}/>
        <div style={{background:C.blueLt,border:`1px solid #BFD6F6`,borderRadius:7,padding:"7px 10px",fontSize:12,color:C.blue,fontWeight:700}}>
          {it.totalPrice?Number(it.totalPrice).toLocaleString():"—"}
        </div>
        <button onClick={()=>removeItem(i)} disabled={form.items.length===1}
          style={{background:"transparent",border:`1px solid ${C.red}44`,borderRadius:6,width:26,height:30,cursor:form.items.length===1?"not-allowed":"pointer",color:C.red,fontSize:14,opacity:form.items.length===1?0.3:1,display:"flex",alignItems:"center",justifyContent:"center"}}>×</button>
      </div>)}
      <button onClick={addItem} style={{border:`1px dashed ${C.border}`,borderRadius:8,padding:"7px",cursor:"pointer",color:C.blue,fontSize:11,background:"transparent",width:"100%",textAlign:"center",marginTop:4}}>+ Add Product</button>
      {grandTotal>0&&<div style={{display:"flex",justifyContent:"flex-end",marginTop:10,paddingTop:10,borderTop:`2px solid ${C.border}`}}>
        <div style={{fontSize:14,fontWeight:700,color:C.ink}}>Grand Total: <span style={{color:C.blue}}>{enq.currency||"USD"} {grandTotal.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</span></div>
      </div>}
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:12}}>
      <div style={{display:"flex",flexDirection:"column",gap:4}}>
        <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Validity (days)</label>
        <input value={form.validity_days} onChange={e=>setF("validity_days",e.target.value)} style={inp}/>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:4}}>
        <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Payment Terms</label>
        <select value={form.paymentTerms} onChange={e=>setF("paymentTerms",e.target.value)} style={{...inp,color:form.paymentTerms?C.ink:C.muted}}>
          <option value="">Select…</option>{PAYMENT_TERMS.map(t=><option key={t} value={t}>{t}</option>)}
        </select>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:4}}>
        <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Incoterms</label>
        <select value={form.incoterms} onChange={e=>setF("incoterms",e.target.value)} style={inp}>
          {INCOTERMS.map(t=><option key={t} value={t}>{t}</option>)}
        </select>
      </div>
    </div>
    <div style={{display:"flex",flexDirection:"column",gap:4,marginBottom:16}}>
      <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Notes / Special Conditions</label>
      <textarea value={form.notes} onChange={e=>setF("notes",e.target.value)} rows={3} placeholder="e.g. Price subject to exchange rate fluctuation. Samples available on request."
        style={{background:C.bg,border:`1px solid ${C.border}`,borderRadius:8,padding:"8px 10px",color:C.ink,fontSize:12,outline:"none",resize:"vertical"}}/>
    </div>
    <div style={{display:"flex",gap:10}}>
      <button onClick={handleSave} disabled={saving} style={{background:C.blue,color:"white",border:"none",borderRadius:8,padding:"9px 18px",cursor:saving?"not-allowed":"pointer",fontSize:13,fontWeight:700,opacity:saving?0.6:1}}>
        {saving?"Saving…":"💾 Save Quotation"}
      </button>
      <button onClick={handleSend} disabled={sending||sent} style={{background:sent?C.green:C.green,color:"white",border:"none",borderRadius:8,padding:"9px 18px",cursor:(sending||sent)?"not-allowed":"pointer",fontSize:13,fontWeight:700,opacity:(sending||sent)?0.8:1}}>
        {sent?"✓ Email Sent!":sending?"Sending…":"📧 Send to Customer"}
      </button>
    </div>
  </div>;
}

// ── EMAIL THREAD TAB ──────────────────────────────────────────────────────────
function EmailThreadTab({enq,threads,onLogEmail}) {
  const enqThreads=threads.filter(t=>t.enquiry_id===enq.id).sort((a,b)=>new Date(a.sent_at)-new Date(b.sent_at));
  const [showLog,setShowLog]=useState(false);
  const [logForm,setLogForm]=useState({direction:"received",subject:"",body:"",from_email:""});
  const [saving,setSaving]=useState(false);

  function setLF(k,v){setLogForm(f=>({...f,[k]:v}));}
  async function handleLog(){
    if(!logForm.subject.trim()||!logForm.body.trim()){alert("Subject and body required.");return;}
    setSaving(true);
    await onLogEmail({enquiry_id:enq.id,customer_name:enq.customer_name,direction:logForm.direction,subject:logForm.subject,body:logForm.body,from_email:logForm.direction==="received"?(logForm.from_email||enq.contact_person||enq.customer_name):"sales@ingredientz.co",to_email:logForm.direction==="received"?"sales@ingredientz.co":(enq.customer_email||enq.contact_person),sent_at:new Date().toISOString()});
    setLogForm({direction:"received",subject:"",body:"",from_email:""});
    setShowLog(false);setSaving(false);
  }

  const inp={background:C.bg,border:`1px solid ${C.border}`,borderRadius:7,padding:"8px 10px",color:C.ink,fontFamily:"Arial,sans-serif",fontSize:12,outline:"none",width:"100%"};

  return <div style={{padding:"16px 0"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.blue,textTransform:"uppercase"}}>Email Thread ({enqThreads.length})</div>
      <button onClick={()=>setShowLog(!showLog)} style={{background:C.blue,color:"white",border:"none",borderRadius:7,padding:"5px 12px",cursor:"pointer",fontSize:11,fontWeight:700}}>+ Log Email</button>
    </div>
    {showLog&&<div style={{background:C.bg,borderRadius:10,padding:14,border:`1px solid ${C.border}`,marginBottom:14}}>
      <div style={{fontSize:10,fontWeight:700,color:C.ink,marginBottom:12}}>Log an Email</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
        <div style={{display:"flex",flexDirection:"column",gap:4}}>
          <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Direction</label>
          <select value={logForm.direction} onChange={e=>setLF("direction",e.target.value)} style={inp}>
            <option value="received">Received (from customer)</option>
            <option value="sent">Sent (by us)</option>
          </select>
        </div>
        {logForm.direction==="received"&&<div style={{display:"flex",flexDirection:"column",gap:4}}>
          <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>From</label>
          <input value={logForm.from_email} onChange={e=>setLF("from_email",e.target.value)} placeholder={enq.contact_person||"Customer name"} style={inp}/>
        </div>}
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:4,marginBottom:10}}>
        <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Subject</label>
        <input value={logForm.subject} onChange={e=>setLF("subject",e.target.value)} placeholder="e.g. Re: Quotation for Ashwagandha Extract" style={inp}/>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:4,marginBottom:12}}>
        <label style={{fontSize:9,fontWeight:700,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>Email Body</label>
        <textarea value={logForm.body} onChange={e=>setLF("body",e.target.value)} rows={4} placeholder="Paste or type the email content here…"
          style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:7,padding:"8px 10px",color:C.ink,fontSize:12,outline:"none",resize:"vertical"}}/>
      </div>
      <div style={{display:"flex",gap:10}}>
        <button onClick={handleLog} disabled={saving} style={{background:C.blue,color:"white",border:"none",borderRadius:7,padding:"8px 16px",cursor:saving?"not-allowed":"pointer",fontSize:12,fontWeight:700}}>{saving?"Saving…":"Save Email"}</button>
        <button onClick={()=>setShowLog(false)} style={{background:"transparent",border:`1px solid ${C.border}`,borderRadius:7,padding:"8px 14px",cursor:"pointer",color:C.muted,fontSize:12}}>Cancel</button>
      </div>
    </div>}
    {enqThreads.length===0
      ?<div style={{textAlign:"center",padding:"32px 16px",color:C.muted,fontSize:12}}>
        No emails yet. Emails sent from the Quotation tab are auto-logged here.<br/>
        <span style={{fontSize:11}}>Manually log received replies using + Log Email.</span>
      </div>
      :<div style={{display:"flex",flexDirection:"column",gap:10}}>
        {enqThreads.map(t=>{
          const isSent=t.direction==="sent"||t.direction==="auto-sent";
          return <div key={t.id} style={{background:isSent?C.blueLt:C.bg,border:`1px solid ${isSent?"#BFD6F6":C.border}`,borderRadius:10,padding:"12px 14px",marginLeft:isSent?24:0,marginRight:isSent?0:24}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:32,height:32,borderRadius:"50%",background:isSent?C.blue:"#E4E6EB",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,color:isSent?"white":C.ink,flexShrink:0}}>
                  {isSent?"I":"C"}
                </div>
                <div>
                  <div style={{fontSize:12,fontWeight:700,color:C.ink}}>{isSent?(t.from_email||"sales@ingredientz.co"):(t.from_email||enq.customer_name)}</div>
                  <div style={{fontSize:10,color:C.muted}}>to {isSent?(t.to_email||enq.contact_person||enq.customer_name):"sales@ingredientz.co"}</div>
                </div>
              </div>
              <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:3}}>
                <div style={{fontSize:10,color:C.muted}}>{fmtDate(t.sent_at)}</div>
                {t.direction==="auto-sent"&&<span style={{background:C.blueLt,color:C.blue,border:`1px solid #BFD6F6`,borderRadius:20,padding:"1px 7px",fontSize:9,fontWeight:700}}>AUTO-SENT</span>}
                {t.direction==="received"&&<span style={{background:"#E4E6EB",color:C.muted,border:`1px solid ${C.border}`,borderRadius:20,padding:"1px 7px",fontSize:9,fontWeight:700}}>RECEIVED</span>}
              </div>
            </div>
            <div style={{fontSize:12,fontWeight:700,color:C.ink,marginBottom:6}}>{t.subject}</div>
            <div style={{fontSize:12,color:C.muted,lineHeight:1.6,whiteSpace:"pre-wrap",maxHeight:100,overflow:"hidden"}}>{t.body}</div>
          </div>;
        })}
      </div>
    }
  </div>;
}

// ── ENQUIRY DRAWER ────────────────────────────────────────────────────────────
function EnquiryDrawer({enq,onClose,onStageChange,onUpdate,customers,users,quotations,threads,onSaveQuotation,onSendQuotationEmail,onLogEmail}) {
  const [drawerTab,setDrawerTab]=useState("details");
  const [editing,setEditing]=useState(false);
  if(!enq)return null;
  const dClose=daysUntil(enq.expected_closure);
  const dRemind=daysUntil(enq.reminder_date);
  const products=Array.isArray(enq.products)?enq.products:[];
  const DTABS=[{id:"details",label:"Details"},{id:"quotation",label:"Quotation"},{id:"thread",label:"Email Thread"}];

  return <div style={{position:"fixed",top:0,right:0,bottom:0,width:520,background:C.white,boxShadow:"-4px 0 20px rgba(0,0,0,0.15)",zIndex:200,overflowY:"auto",borderLeft:`1px solid ${C.border}`,display:"flex",flexDirection:"column"}}>
    <div style={{padding:"20px 22px 0",flexShrink:0}}>
      {!editing&&<div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14}}>
        <div>
          <div style={{fontSize:19,fontWeight:700,color:C.ink}}>{enq.customer_name}</div>
          <div style={{fontSize:12,color:C.muted,marginTop:2}}>{enq.contact_person}{enq.country?` · ${enq.country}`:""}</div>
          <div style={{display:"flex",gap:7,marginTop:8,flexWrap:"wrap"}}><StageBadge stage={enq.stage}/><PrioBadge priority={enq.priority}/></div>
        </div>
        <div style={{display:"flex",gap:7}}>
          <Btn label="Edit" onClick={()=>setEditing(true)} size="sm" variant="ghost"/>
          <button onClick={onClose} style={{background:"transparent",border:`1px solid ${C.border}`,borderRadius:"50%",width:32,height:32,cursor:"pointer",color:C.muted,fontSize:17,display:"flex",alignItems:"center",justifyContent:"center"}}>×</button>
        </div>
      </div>}
      {!editing&&<div style={{display:"flex",gap:0,borderBottom:`1px solid ${C.border}`}}>
        {DTABS.map(t=><button key={t.id} onClick={()=>setDrawerTab(t.id)} style={{background:"transparent",border:"none",borderBottom:drawerTab===t.id?`2px solid ${C.blue}`:"2px solid transparent",padding:"8px 16px",cursor:"pointer",fontSize:12,fontWeight:drawerTab===t.id?700:400,color:drawerTab===t.id?C.blue:C.muted,marginBottom:-1}}>{t.label}</button>)}
      </div>}
    </div>
    <div style={{flex:1,overflowY:"auto",padding:"0 22px 22px"}}>
      {editing
        ?<div style={{paddingTop:16}}><EnquiryForm onSave={async(row)=>{await onUpdate(enq.id,row);setEditing(false);}} onClose={()=>setEditing(false)} customers={customers} users={users} initial={enq}/></div>
        :drawerTab==="details"
          ?<div style={{paddingTop:14}}>
            {dRemind!==null&&dRemind<=0&&<div style={{background:"#FFF0F0",border:`1px solid #FFDAD9`,borderRadius:9,padding:"9px 14px",marginBottom:10,fontSize:12,color:C.red,fontWeight:600}}>🔔 Reminder overdue by {Math.abs(dRemind)} day{Math.abs(dRemind)!==1?"s":""}</div>}
            {dClose!==null&&dClose<=7&&dClose>0&&<div style={{background:"#FFF8E7",border:`1px solid #FFE0A3`,borderRadius:9,padding:"9px 14px",marginBottom:10,fontSize:12,color:C.amber,fontWeight:600}}>⚡ Closes in {dClose} day{dClose!==1?"s":""}</div>}
            <div style={{background:C.bg,borderRadius:11,padding:14,border:`1px solid ${C.border}`,marginBottom:12}}>
              <div style={{fontSize:9,color:C.blue,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:9}}>Products ({products.length})</div>
              {products.map((p,i)=><div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"5px 0",borderBottom:i<products.length-1?`1px solid ${C.border}`:"none"}}>
                <div style={{fontSize:12,color:C.ink}}><span style={{color:C.blue,fontSize:10,marginRight:7,fontWeight:700}}>#{i+1}</span>{p.name}</div>
                {p.qty&&<span style={{fontSize:11,color:C.muted,background:C.white,border:`1px solid ${C.border}`,borderRadius:6,padding:"2px 9px"}}>{p.qty} {p.unit}</span>}
              </div>)}
              {enq.expected_value&&<div style={{marginTop:9,paddingTop:9,borderTop:`1px solid ${C.border}`,fontSize:12}}>
                <span style={{color:C.muted}}>Value: </span><span style={{color:C.blue,fontWeight:700}}>{enq.currency} {Number(enq.expected_value).toLocaleString()}</span>
              </div>}
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,marginBottom:12}}>
              {[["Date Received",fmtDate(enq.enquiry_date)],["Assigned To",enq.assigned_to],["Source",enq.source],["Closure",fmtDate(enq.expected_closure)],["Reminder",fmtDate(enq.reminder_date)],["Quotation",enq.quotation_sent?"Yes":"No"],["Created By",enq.created_by]].map(([k,v])=>(
                <div key={k} style={{background:C.bg,borderRadius:9,padding:"9px 12px",border:`1px solid ${C.border}`}}>
                  <div style={{fontSize:9,color:C.muted,fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:3}}>{k}</div>
                  <div style={{fontSize:12,color:C.ink}}>{v||"—"}</div>
                </div>
              ))}
            </div>
            {enq.notes&&<div style={{background:C.bg,borderRadius:11,padding:12,border:`1px solid ${C.border}`,marginBottom:14}}>
              <div style={{fontSize:9,color:C.muted,fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:5}}>Notes</div>
              <div style={{fontSize:12,color:C.muted,lineHeight:1.6}}>{enq.notes}</div>
            </div>}
            <div style={{borderTop:`1px solid ${C.border}`,paddingTop:14}}>
              <div style={{fontSize:9,color:C.muted,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:9}}>Update Stage</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                {STAGES.map((s,i)=><button key={s} onClick={()=>onStageChange(enq.id,s)} style={{background:enq.stage===s?`${STAGE_COLORS[i]}22`:"transparent",color:enq.stage===s?STAGE_COLORS[i]:C.muted,border:`1px solid ${enq.stage===s?STAGE_COLORS[i]+"66":C.border}`,borderRadius:20,padding:"4px 12px",cursor:"pointer",fontSize:11,fontWeight:enq.stage===s?700:400}}>{s}</button>)}
              </div>
            </div>
          </div>
          :drawerTab==="quotation"
            ?<QuotationTab enq={enq} quotations={quotations} onSave={onSaveQuotation} onSendEmail={onSendQuotationEmail} users={users}/>
            :<EmailThreadTab enq={enq} threads={threads} onLogEmail={onLogEmail}/>
      }
    </div>
  </div>;
}

// ── DASHBOARD ─────────────────────────────────────────────────────────────────
function Dashboard({enquiries,users,tasks,onTaskAdd,onTaskUpdate,onTaskDelete}) {
  const active=enquiries.filter(e=>!["PO Received","Lost","No Response","Out of Scope"].includes(e.stage));
  const totalVal=enquiries.filter(e=>e.stage!=="Lost").reduce((s,e)=>s+(+e.expected_value||0),0);
  const poReceived=enquiries.filter(e=>e.stage==="PO Received").length;
  const overdueEnq=enquiries.filter(e=>{const d=daysUntil(e.reminder_date);return d!==null&&d<=0&&!["PO Received","Lost"].includes(e.stage);});
  const closingSoon=enquiries.filter(e=>{const d=daysUntil(e.expected_closure);return d!==null&&d<=7&&d>=0&&!["PO Received","Lost"].includes(e.stage);});
  const stageCounts=STAGES.map((s,i)=>({stage:s.split(" ")[0],count:enquiries.filter(e=>e.stage===s).length,color:STAGE_COLORS[i]})).filter(s=>s.count>0);
  const assigneeCounts=users.filter(u=>u.active).map(u=>({name:u.name.split(" ")[0],count:enquiries.filter(e=>e.assigned_to===u.name).length})).filter(u=>u.count>0);
  const CT=({active:a,payload})=>a&&payload?.length?<div style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:7,padding:"7px 12px",fontSize:11,color:C.ink,boxShadow:"0 2px 8px rgba(0,0,0,0.1)"}}>{payload[0].name||payload[0].dataKey}: <b style={{color:C.blue}}>{payload[0].value}</b></div>:null;

  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12}}>
      <KPI label="Total Enquiries" value={enquiries.length} sub={`${active.length} active`}/>
      <KPI label="Pipeline Value" value={`$${Math.round(totalVal/1000)}K`} sub="Excl. lost" accent={C.blue}/>
      <KPI label="PO Received" value={poReceived} sub="Orders confirmed" accent={C.green}/>
      <KPI label="Overdue Follow-ups" value={overdueEnq.length} sub={`${closingSoon.length} closing this week`} accent={overdueEnq.length>0?C.red:C.green}/>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"2fr 1fr",gap:12}}>
      <Card style={{padding:16}}>
        <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.blue,textTransform:"uppercase",marginBottom:14}}>Pipeline by Stage</div>
        <ResponsiveContainer width="100%" height={170}>
          <BarChart data={stageCounts} margin={{top:4,right:8,bottom:4,left:-22}}>
            <CartesianGrid stroke={C.border} strokeDasharray="3 3"/>
            <XAxis dataKey="stage" tick={{fill:C.muted,fontSize:9}}/>
            <YAxis tick={{fill:C.muted,fontSize:9}}/>
            <Tooltip content={<CT/>}/>
            <Bar dataKey="count" radius={[4,4,0,0]}>{stageCounts.map((s,i)=><Cell key={i} fill={s.color}/>)}</Bar>
          </BarChart>
        </ResponsiveContainer>
      </Card>
      <Card style={{padding:16}}>
        <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.blue,textTransform:"uppercase",marginBottom:12}}>By Assignee</div>
        <ResponsiveContainer width="100%" height={150}>
          <PieChart><Pie data={assigneeCounts} cx="50%" cy="50%" outerRadius={58} dataKey="count" nameKey="name" paddingAngle={3}>{assigneeCounts.map((_,i)=><Cell key={i} fill={[C.blue,C.green,"#E2C47A",C.amber,"#9B59B6",C.muted][i%6]}/>)}</Pie><Tooltip content={<CT/>}/></PieChart>
        </ResponsiveContainer>
        <div style={{display:"flex",flexDirection:"column",gap:3}}>
          {assigneeCounts.map((a,i)=><div key={a.name} style={{display:"flex",justifyContent:"space-between",fontSize:10}}>
            <span style={{color:[C.blue,C.green,"#E2C47A",C.amber,"#9B59B6",C.muted][i%6]}}>● {a.name}</span>
            <span style={{color:C.ink,fontWeight:700}}>{a.count}</span>
          </div>)}
        </div>
      </Card>
    </div>
    {overdueEnq.length>0&&<Card style={{padding:16,border:`1px solid #FFDAD9`,background:"#FFF8F8"}}>
      <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.red,textTransform:"uppercase",marginBottom:12}}>🔔 Overdue Follow-ups ({overdueEnq.length})</div>
      {overdueEnq.map(e=><div key={e.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:C.white,borderRadius:9,padding:"9px 14px",border:`1px solid #FFDAD9`,marginBottom:7}}>
        <div><div style={{fontSize:12,color:C.ink,fontWeight:600}}>{e.customer_name}</div><div style={{fontSize:11,color:C.muted}}>{(e.products||[])[0]?.name||"—"} · {e.assigned_to}</div></div>
        <div style={{textAlign:"right"}}><div style={{fontSize:11,color:C.red,fontWeight:700}}>Overdue {Math.abs(daysUntil(e.reminder_date))}d</div><StageBadge stage={e.stage}/></div>
      </div>)}
    </Card>}
    {closingSoon.length>0&&<Card style={{padding:16,border:`1px solid #FFE0A3`,background:"#FFFBF0"}}>
      <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.amber,textTransform:"uppercase",marginBottom:12}}>⚡ Closing This Week ({closingSoon.length})</div>
      {closingSoon.map(e=><div key={e.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:C.white,borderRadius:9,padding:"9px 14px",border:`1px solid #FFE0A3`,marginBottom:7}}>
        <div><div style={{fontSize:12,color:C.ink,fontWeight:600}}>{e.customer_name}</div><div style={{fontSize:11,color:C.muted}}>{(e.products||[])[0]?.name||"—"} · {e.assigned_to}</div></div>
        <div style={{textAlign:"right"}}><div style={{fontSize:11,color:C.amber,fontWeight:700}}>{daysUntil(e.expected_closure)}d left</div><div style={{fontSize:12,color:C.blue,fontWeight:700}}>{e.currency} {Number(e.expected_value||0).toLocaleString()}</div></div>
      </div>)}
    </Card>}
    <TaskBoard tasks={tasks} users={users} onAdd={onTaskAdd} onUpdate={onTaskUpdate} onDelete={onTaskDelete}/>
  </div>;
}

// ── ENQUIRIES TAB ─────────────────────────────────────────────────────────────
function EnquiriesTab({enquiries,customers,users,onSelect,onStageChange,onDelete,onAdd}) {
  const [showForm,setShowForm]=useState(false);
  const [search,setSearch]=useState("");
  const [filterStage,setFilterStage]=useState("");
  const [filterAssignee,setFilterAssignee]=useState("");
  const [sort,setSort]=useState({k:"created_at",d:-1});

  const filtered=enquiries
    .filter(e=>(!filterStage||e.stage===filterStage)&&(!filterAssignee||e.assigned_to===filterAssignee))
    .filter(e=>!search||[e.customer_name,(e.products||[])[0]?.name||"",e.assigned_to,e.country].join(" ").toLowerCase().includes(search.toLowerCase()))
    .sort((a,b)=>{const va=a[sort.k]??"",vb=b[sort.k]??"";return typeof va==="number"?(va-vb)*sort.d:String(va).localeCompare(String(vb))*sort.d;});

  function toggleSort(k){setSort(s=>s.k===k?{k,d:s.d*-1}:{k,d:-1});}
  const selStyle={background:C.white,border:`1px solid ${C.border}`,borderRadius:7,padding:"6px 10px",color:C.ink,fontSize:11};

  return <div>
    {showForm&&<Modal title="New Enquiry" sub="Saves to Supabase · Unlimited products" onClose={()=>setShowForm(false)} width={880}>
      <EnquiryForm onSave={async(row)=>{await onAdd(row);setShowForm(false);}} onClose={()=>setShowForm(false)} customers={customers} users={users}/>
    </Modal>}
    <Card style={{overflow:"hidden"}}>
      <div style={{padding:"14px 18px",display:"flex",gap:10,alignItems:"center",borderBottom:`1px solid ${C.border}`,flexWrap:"wrap"}}>
        <div style={{fontSize:18,fontWeight:700,color:C.ink}}>Enquiries <span style={{fontSize:12,color:C.blue,fontWeight:400}}>{filtered.length} records</span></div>
        <Btn label="+ New Enquiry" onClick={()=>setShowForm(true)} size="sm"/>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search…" style={{marginLeft:"auto",background:C.bg,border:`1px solid ${C.border}`,borderRadius:7,padding:"6px 12px",color:C.ink,fontSize:12,outline:"none",width:170}}/>
        <select value={filterStage} onChange={e=>setFilterStage(e.target.value)} style={selStyle}><option value="">All Stages</option>{STAGES.map(s=><option key={s} value={s}>{s}</option>)}</select>
        <select value={filterAssignee} onChange={e=>setFilterAssignee(e.target.value)} style={selStyle}><option value="">All Team</option>{users.filter(u=>u.active).map(u=><option key={u.id} value={u.name}>{u.name.split(" ")[0]}</option>)}</select>
      </div>
      <div style={{overflowX:"auto",maxHeight:500,overflowY:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead style={{position:"sticky",top:0,background:C.bg,zIndex:2}}>
            <tr>{[["enquiry_date","Date"],["customer_name","Customer"],["products","Product"],["country","Country"],["assigned_to","Assigned"],["priority","Priority"],["stage","Stage"],["expected_value","Value"],["expected_closure","Closure"],["reminder_date","Reminder"]].map(([k,l])=>(
              <th key={k} onClick={()=>toggleSort(k)} style={{padding:"9px 13px",textAlign:"left",cursor:"pointer",color:sort.k===k?C.blue:C.muted,borderBottom:`1px solid ${C.border}`,fontWeight:700,letterSpacing:1,fontSize:9,textTransform:"uppercase",userSelect:"none",whiteSpace:"nowrap"}}>
                {l}{sort.k===k?(sort.d===1?" ↑":" ↓"):""}
              </th>))}
              <th style={{padding:"9px 13px",borderBottom:`1px solid ${C.border}`}}></th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((e,i)=>{
              const dR=daysUntil(e.reminder_date);
              const dC=daysUntil(e.expected_closure);
              const overR=dR!==null&&dR<=0&&!["PO Received","Lost"].includes(e.stage);
              const closeS=dC!==null&&dC<=7&&dC>=0&&!["PO Received","Lost"].includes(e.stage);
              const prod=(e.products||[])[0]?.name||"—";
              const prod2=(e.products||[])[1]?.name;
              return <tr key={e.id} onClick={()=>onSelect(e)}
                style={{background:overR?"#FFF8F8":closeS?"#FFFBF0":i%2===0?C.bg:"transparent",cursor:"pointer"}}
                onMouseEnter={ev=>ev.currentTarget.style.background=C.blueLt}
                onMouseLeave={ev=>ev.currentTarget.style.background=overR?"#FFF8F8":closeS?"#FFFBF0":i%2===0?C.bg:"transparent"}>
                <td style={{padding:"9px 13px",color:C.muted,whiteSpace:"nowrap"}}>{fmtDate(e.enquiry_date)}</td>
                <td style={{padding:"9px 13px",color:C.ink,fontWeight:600,maxWidth:130,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{e.customer_name}</td>
                <td style={{padding:"9px 13px",color:C.muted,maxWidth:150,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{prod}{prod2?`, ${prod2}`:""}</td>
                <td style={{padding:"9px 13px",color:C.muted}}>{e.country||"—"}</td>
                <td style={{padding:"9px 13px",color:C.muted}}>{(e.assigned_to||"").split(" ")[0]||"—"}</td>
                <td style={{padding:"9px 13px"}}><PrioBadge priority={e.priority}/></td>
                <td style={{padding:"9px 13px"}} onClick={ev=>ev.stopPropagation()}>
                  <select value={e.stage} onChange={ev=>onStageChange(e.id,ev.target.value)} style={{background:"transparent",border:"none",cursor:"pointer",fontSize:11,color:STAGE_COLORS[STAGES.indexOf(e.stage)]||C.muted,padding:0}}>
                    {STAGES.map(s=><option key={s} value={s}>{s}</option>)}
                  </select>
                </td>
                <td style={{padding:"9px 13px",color:C.blue,fontWeight:700}}>{e.expected_value?`${e.currency||"$"}${Number(e.expected_value).toLocaleString()}`:"—"}</td>
                <td style={{padding:"9px 13px",color:closeS?C.amber:C.muted,fontWeight:closeS?700:400}}>{fmtDate(e.expected_closure)}</td>
                <td style={{padding:"9px 13px",color:overR?C.red:C.muted,fontWeight:overR?700:400}}>{overR?`⚠ ${Math.abs(dR)}d overdue`:fmtDate(e.reminder_date)}</td>
                <td style={{padding:"9px 13px"}} onClick={ev=>ev.stopPropagation()}>
                  <button onClick={()=>onDelete(e.id)} style={{background:"transparent",border:`1px solid ${C.red}44`,borderRadius:5,padding:"3px 7px",cursor:"pointer",color:C.red,fontSize:10}}>✕</button>
                </td>
              </tr>;
            })}
          </tbody>
        </table>
        {filtered.length===0&&<div style={{padding:36,textAlign:"center",color:C.muted,fontSize:12}}>No enquiries match your filters</div>}
      </div>
    </Card>
  </div>;
}

// ── REMINDERS TAB ─────────────────────────────────────────────────────────────
function RemindersTab({enquiries,onSelect}) {
  const active=enquiries.filter(e=>!["PO Received","Lost","No Response","Out of Scope"].includes(e.stage)&&e.reminder_date);
  const sorted=[...active].sort((a,b)=>new Date(a.reminder_date)-new Date(b.reminder_date));
  const overdue=sorted.filter(e=>daysUntil(e.reminder_date)<=0);
  const upcoming=sorted.filter(e=>daysUntil(e.reminder_date)>0);
  function Row({e,over}){
    const d=daysUntil(e.reminder_date);
    return <div onClick={()=>onSelect(e)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:over?"#FFF8F8":C.bg,borderRadius:10,padding:"12px 16px",border:`1px solid ${over?"#FFDAD9":C.border}`,cursor:"pointer",marginBottom:7}}
      onMouseEnter={ev=>ev.currentTarget.style.background=C.blueLt}
      onMouseLeave={ev=>ev.currentTarget.style.background=over?"#FFF8F8":C.bg}>
      <div style={{display:"flex",alignItems:"center",gap:12}}>
        <div style={{width:38,height:38,borderRadius:"50%",background:over?"#FFDAD9":C.blueLt,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>{over?"⚠":"🔔"}</div>
        <div>
          <div style={{fontSize:13,color:C.ink,fontWeight:600}}>{e.customer_name}</div>
          <div style={{fontSize:11,color:C.muted}}>{(e.products||[])[0]?.name||"—"} · {e.assigned_to}</div>
        </div>
      </div>
      <div style={{textAlign:"right"}}>
        <div style={{fontSize:12,color:over?C.red:C.amber,fontWeight:700}}>{over?`${Math.abs(d)}d overdue`:`In ${d} day${d!==1?"s":""}`}</div>
        <div style={{marginTop:4}}><StageBadge stage={e.stage}/></div>
      </div>
    </div>;
  }
  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    {overdue.length>0&&<Card style={{padding:16,border:`1px solid #FFDAD9`}}>
      <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.red,textTransform:"uppercase",marginBottom:12}}>⚠ Overdue ({overdue.length})</div>
      {overdue.map(e=><Row key={e.id} e={e} over={true}/>)}
    </Card>}
    <Card style={{padding:16}}>
      <div style={{fontSize:9,fontWeight:700,letterSpacing:2,color:C.blue,textTransform:"uppercase",marginBottom:12}}>Upcoming ({upcoming.length})</div>
      {upcoming.length>0?upcoming.map(e=><Row key={e.id} e={e} over={false}/>):<div style={{fontSize:12,color:C.muted,textAlign:"center",padding:20}}>No upcoming reminders</div>}
    </Card>
  </div>;
}

// ── CUSTOMERS TAB ─────────────────────────────────────────────────────────────
function CustomersTab({customers,onAdd,onUpdate,onDelete}) {
  const [modal,setModal]=useState(null);
  const [search,setSearch]=useState("");
  const filtered=customers.filter(c=>!search||[c.company,c.country,c.contact,c.email].join(" ").toLowerCase().includes(search.toLowerCase()));
  return <div>
    {modal&&<Modal title={modal.type==="edit"?"Edit Customer":"Add Customer"} onClose={()=>setModal(null)}>
      <CustomerForm onSave={async(form,id)=>{id?await onUpdate(id,form):await onAdd(form);setModal(null);}} onClose={()=>setModal(null)} initial={modal.type==="edit"?modal.data:null}/>
    </Modal>}
    <Card style={{overflow:"hidden"}}>
      <div style={{padding:"14px 18px",display:"flex",gap:10,alignItems:"center",borderBottom:`1px solid ${C.border}`}}>
        <div style={{fontSize:18,fontWeight:700,color:C.ink}}>Customers <span style={{fontSize:12,color:C.blue,fontWeight:400}}>{customers.length} companies</span></div>
        <Btn label="+ Add Customer" onClick={()=>setModal({type:"add"})} size="sm"/>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search…" style={{marginLeft:"auto",background:C.bg,border:`1px solid ${C.border}`,borderRadius:7,padding:"6px 12px",color:C.ink,fontSize:12,outline:"none",width:200}}/>
      </div>
      <div style={{overflowX:"auto",maxHeight:500,overflowY:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead style={{position:"sticky",top:0,background:C.bg,zIndex:2}}>
            <tr>{["Company","Country","Contact","Email","Phone",""].map(h=><th key={h} style={{padding:"9px 14px",textAlign:"left",color:C.muted,borderBottom:`1px solid ${C.border}`,fontWeight:700,letterSpacing:1,fontSize:9,textTransform:"uppercase"}}>{h}</th>)}</tr>
          </thead>
          <tbody>
            {filtered.map((c,i)=><tr key={c.id} style={{background:i%2===0?C.bg:"transparent"}}>
              <td style={{padding:"9px 14px",color:C.ink,fontWeight:600}}>{c.company}</td>
              <td style={{padding:"9px 14px",color:C.muted}}>{c.country||"—"}</td>
              <td style={{padding:"9px 14px",color:C.muted}}>{c.contact||"—"}</td>
              <td style={{padding:"9px 14px",color:C.muted}}>{c.email||"—"}</td>
              <td style={{padding:"9px 14px",color:C.muted}}>{c.phone||"—"}</td>
              <td style={{padding:"9px 14px",display:"flex",gap:6}}>
                <Btn label="Edit" onClick={()=>setModal({type:"edit",data:c})} size="sm" variant="ghost"/>
                <Btn label="✕" onClick={()=>onDelete(c.id)} size="sm" variant="danger"/>
              </td>
            </tr>)}
          </tbody>
        </table>
        {filtered.length===0&&<div style={{padding:30,textAlign:"center",color:C.muted,fontSize:12}}>No customers yet</div>}
      </div>
    </Card>
  </div>;
}

// ── USERS TAB ─────────────────────────────────────────────────────────────────
function UsersTab({users,onAdd,onUpdate,onDelete}) {
  const [modal,setModal]=useState(null);
  return <div>
    {modal&&<Modal title={modal.type==="edit"?"Edit User":"Add Team Member"} onClose={()=>setModal(null)}>
      <UserForm onSave={async(form,id)=>{id?await onUpdate(id,form):await onAdd(form);setModal(null);}} onClose={()=>setModal(null)} initial={modal.type==="edit"?modal.data:null}/>
    </Modal>}
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <div style={{fontSize:18,fontWeight:700,color:C.ink}}>Team Members <span style={{fontSize:12,color:C.blue,fontWeight:400}}>{users.length} users</span></div>
      <Btn label="+ Add User" onClick={()=>setModal({type:"add"})} size="sm"/>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))",gap:12}}>
      {users.map(u=><Card key={u.id} style={{padding:18}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
          <div style={{width:42,height:42,borderRadius:"50%",background:C.blue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:700,color:"white"}}>{u.name.charAt(0)}</div>
          <span style={{background:u.active?"#E6F4EA":C.bg,color:u.active?C.green:C.muted,border:`1px solid ${u.active?"#C3E6CB":C.border}`,borderRadius:20,padding:"2px 10px",fontSize:10,fontWeight:700}}>{u.active?"Active":"Inactive"}</span>
        </div>
        <div style={{fontSize:14,fontWeight:700,color:C.ink,marginBottom:3}}>{u.name}</div>
        <div style={{fontSize:11,color:C.muted,marginBottom:2}}>{u.email}</div>
        <div style={{fontSize:10,color:C.blue,letterSpacing:1,textTransform:"uppercase",marginBottom:4}}>{u.role}</div>
        <div style={{fontSize:10,color:C.muted,marginBottom:13}}>Sends from: {u.sender_email}</div>
        <div style={{display:"flex",gap:7}}>
          <Btn label="Edit" onClick={()=>setModal({type:"edit",data:u})} size="sm" variant="ghost"/>
          <Btn label="Remove" onClick={()=>onDelete(u.id)} size="sm" variant="danger"/>
        </div>
      </Card>)}
    </div>
  </div>;
}

// ── MAIN APP ──────────────────────────────────────────────────────────────────
export default function App() {
  const [loading,setLoading]=useState(true);
  const [toast,setToast]=useState(null);
  const [enquiries,setEnquiries]=useState([]);
  const [customers,setCustomers]=useState([]);
  const [users,setUsers]=useState([]);
  const [tasks,setTasks]=useState([]);
  const [quotations,setQuotations]=useState([]);
  const [threads,setThreads]=useState([]);
  const [activeTab,setActiveTab]=useState("dashboard");
  const [selectedEnq,setSelectedEnq]=useState(null);

  function showToast(msg,err=false){setToast({msg,err});setTimeout(()=>setToast(null),3000);}

  useEffect(()=>{
    Promise.all([
      dbGet("enquiries"),dbGet("customers"),dbGet("users"),
      dbGet("tasks"),dbGet("quotations"),dbGet("email_threads")
    ]).then(([enqs,custs,usrs,tsks,quots,thrs])=>{
      setEnquiries(enqs);setCustomers(custs);setUsers(usrs);
      setTasks(tsks);setQuotations(quots);setThreads(thrs);
    }).finally(()=>setLoading(false));
  },[]);

  // ── Enquiry ops ──
  async function addEnquiry(row){
    const data=await dbInsert("enquiries",row);
    if(data){setEnquiries(p=>[data,...p]);showToast(`✓ Enquiry saved — ${row.customer_name}`);
      // notify assigned person
      const sender=getSenderEmail(row.assigned_to,users);
      const u=users.find(x=>x.name===row.assigned_to);
      if(u?.email){
        sendEmail({from:`Ingredientz CRM <${sender}>`,to:u.email,subject:`New Enquiry Assigned — ${row.customer_name}`,
          html:buildEmailHtml("New Enquiry Assigned","#1877F2",[`<b>Hi ${row.assigned_to?.split(" ")[0]},</b> a new enquiry has been assigned to you.`,`<b>Customer:</b> ${row.customer_name} (${row.country||"—"})`,`<b>Product:</b> ${(row.products||[])[0]?.name||"—"}`,`<b>Priority:</b> ${row.priority}`,`<b>Stage:</b> ${row.stage}`],"Ingredientz CRM · Auto-notification"),
          text:`New enquiry assigned: ${row.customer_name}`});
      }
    }
  }
  async function updateEnquiry(id,row){
    await dbUpdate("enquiries",id,row);
    setEnquiries(p=>p.map(e=>e.id===id?{...e,...row}:e));
    if(selectedEnq?.id===id)setSelectedEnq(s=>({...s,...row}));
    showToast("✓ Enquiry updated");
  }
  async function deleteEnquiry(id){await dbDelete("enquiries",id);setEnquiries(p=>p.filter(e=>e.id!==id));if(selectedEnq?.id===id)setSelectedEnq(null);}
  async function stageChange(id,stage){
    await dbUpdate("enquiries",id,{stage});
    setEnquiries(p=>p.map(e=>e.id===id?{...e,stage}:e));
    if(selectedEnq?.id===id)setSelectedEnq(s=>s?{...s,stage}:s);
    // notify
    const enq=enquiries.find(e=>e.id===id);
    if(enq){
      const sender=getSenderEmail(enq.assigned_to,users);
      const u=users.find(x=>x.name===enq.assigned_to);
      if(u?.email){
        sendEmail({from:`Ingredientz CRM <${sender}>`,to:u.email,subject:`Stage Updated — ${enq.customer_name} — ${stage}`,
          html:buildEmailHtml("Enquiry Stage Updated","#1877F2",[`<b>Hi ${(enq.assigned_to||"").split(" ")[0]},</b> an enquiry stage has been updated.`,`<b>Customer:</b> ${enq.customer_name}`,`<b>New Stage:</b> ${stage}`],"Ingredientz CRM · Auto-notification"),
          text:`Stage updated: ${enq.customer_name} → ${stage}`});
      }
    }
  }

  // ── Task ops ──
  async function addTask(row){const data=await dbInsert("tasks",row);if(data){setTasks(p=>[data,...p]);
    const sender=getSenderEmail(row.owner,users);const u=users.find(x=>x.name===row.owner);
    if(u?.email){sendEmail({from:`Ingredientz CRM <${sender}>`,to:u.email,subject:`New Task Assigned — ${row.task.slice(0,50)}`,html:buildEmailHtml("New Task Assigned","#1877F2",[`<b>Hi ${row.owner?.split(" ")[0]},</b> a new task has been assigned.`,`<b>Task:</b> ${row.task}`,`<b>Priority:</b> ${row.priority}`,`<b>Due:</b> ${row.due_date||"—"}`],"Ingredientz CRM"),text:`New task: ${row.task}`});}}}
  async function updateTask(id,row){await dbUpdate("tasks",id,row);setTasks(p=>p.map(t=>t.id===id?{...t,...row}:t));}
  async function deleteTask(id){await dbDelete("tasks",id);setTasks(p=>p.filter(t=>t.id!==id));}

  // ── Customer ops ──
  async function addCustomer(row){const data=await dbInsert("customers",row);if(data){setCustomers(p=>[data,...p]);showToast(`✓ ${row.company} added`);}}
  async function updateCustomer(id,row){await dbUpdate("customers",id,row);setCustomers(p=>p.map(c=>c.id===id?{...c,...row}:c));}
  async function deleteCustomer(id){await dbDelete("customers",id);setCustomers(p=>p.filter(c=>c.id!==id));}

  // ── User ops ──
  async function addUser(row){const data=await dbInsert("users",row);if(data){setUsers(p=>[data,...p]);showToast(`✓ ${row.name} added`);}}
  async function updateUser(id,row){await dbUpdate("users",id,row);setUsers(p=>p.map(u=>u.id===id?{...u,...row}:u));}
  async function deleteUser(id){await dbDelete("users",id);setUsers(p=>p.filter(u=>u.id!==id));}

  // ── Quotation ops ──
  async function saveQuotation(row){
    const data=await dbInsert("quotations",row);
    if(data){setQuotations(p=>[data,...p]);showToast(`✓ Quotation v${row.version} saved`);
      await stageChange(row.enquiry_id,"Quotation Sent");}
  }

  async function sendQuotationEmail(enq,form,grandTotal,users){
    const sender=getSenderEmail(enq.assigned_to,users);
    const custEmail=customers.find(c=>c.id===enq.customer_id)?.email||"";
    const itemLines=form.items.map(it=>`${it.name} — ${it.qty} ${it.unit} @ ${enq.currency||"USD"} ${it.unitPrice} = ${enq.currency||"USD"} ${it.totalPrice}`).join("<br/>");
    const subject=`Quotation — ${(enq.products||[])[0]?.name||"Products"} — ${enq.customer_name}`;
    const itemsText=form.items.map(function(it){return it.name+" - "+it.qty+" "+it.unit+" @ "+(enq.currency||"USD")+" "+it.unitPrice;}).join(", ");
    const bodyText="Dear "+(enq.contact_person||enq.customer_name)+",\n\nThank you for your enquiry. Please find our quotation below.\n\nProducts:\n"+itemsText+"\n\nGrand Total: "+(enq.currency||"USD")+" "+grandTotal.toLocaleString(undefined,{minimumFractionDigits:2})+"\nValidity: "+form.validity_days+" days\nPayment Terms: "+(form.paymentTerms||"To be discussed")+"\nIncoterms: "+form.incoterms+(form.notes?"\n\nNotes: "+form.notes:"")+"\n\nKind regards,\nIngredientz Sales Team\n"+sender;
    const html=buildEmailHtml(subject,"#1877F2",[`Dear <b>${enq.contact_person||enq.customer_name}</b>,`,`Thank you for your enquiry. Please find our quotation below.`,`<b>Products:</b><br/>${itemLines}`,`<b>Grand Total: ${enq.currency||"USD"} ${grandTotal.toLocaleString(undefined,{minimumFractionDigits:2})}</b>`,`<b>Validity:</b> ${form.validity_days} days`,`<b>Payment Terms:</b> ${form.paymentTerms||"To be discussed"}`,`<b>Incoterms:</b> ${form.incoterms}`,form.notes?`<b>Notes:</b> ${form.notes}`:""].filter(Boolean),`Ingredientz Inc · ${sender}`);

    if(custEmail){
      const res=await sendEmail({from:`Ingredientz Sales <${sender}>`,to:custEmail,subject,html,text:bodyText});
      showToast(res?.id?`✓ Quotation sent to ${custEmail}`:`✓ Quotation logged (email not sent — check customer email)`);
    } else {
      showToast("⚠ No customer email — quotation logged only");
    }
    // Log in thread
    const threadRow={enquiry_id:enq.id,customer_name:enq.customer_name,direction:"auto-sent",subject,body:bodyText,from_email:sender,to_email:custEmail||enq.contact_person,sent_at:new Date().toISOString()};
    const data=await dbInsert("email_threads",threadRow);
    if(data)setThreads(p=>[data,...p]);
  }

  async function logEmail(row){const data=await dbInsert("email_threads",row);if(data){setThreads(p=>[data,...p]);showToast("✓ Email logged");}}

  async function handleRefresh(){
    setLoading(true);
    const [enqs,custs,usrs,tsks,quots,thrs]=await Promise.all([dbGet("enquiries"),dbGet("customers"),dbGet("users"),dbGet("tasks"),dbGet("quotations"),dbGet("email_threads")]);
    setEnquiries(enqs);setCustomers(custs);setUsers(usrs);setTasks(tsks);setQuotations(quots);setThreads(thrs);
    setLoading(false);showToast("✓ Synced from Supabase");
  }

  const overdueTaskCount=tasks.filter(t=>t.status!=="Done"&&t.due_date&&daysUntil(t.due_date)<0).length;
  const overdueReminderCount=enquiries.filter(e=>{const d=daysUntil(e.reminder_date);return d!==null&&d<=0&&!["PO Received","Lost"].includes(e.stage);}).length;
  const TABS=[
    {id:"dashboard",label:"Dashboard",icon:"◈",badge:overdueTaskCount>0?overdueTaskCount:0},
    {id:"enquiries",label:"Enquiries",icon:"📋",badge:0},
    {id:"reminders",label:"Reminders",icon:"🔔",badge:overdueReminderCount},
    {id:"customers",label:"Customers",icon:"🏢",badge:0},
    {id:"users",label:"Team",icon:"👥",badge:0},
  ];

  return <div style={{minHeight:"100vh",background:C.bg,fontFamily:"Arial,sans-serif"}}>
    {toast&&<div style={{position:"fixed",top:18,right:18,zIndex:999,background:toast.err?C.red:C.green,color:"white",borderRadius:9,padding:"9px 18px",fontSize:12,fontWeight:600,boxShadow:"0 4px 16px rgba(0,0,0,0.2)"}}>{toast.msg}</div>}
    {loading&&<div style={{position:"fixed",inset:0,background:"rgba(24,119,242,0.96)",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:14}}>
      <img src={LOGO} alt="Ingredientz" style={{height:50,objectFit:"contain",background:"white",borderRadius:8,padding:"6px 16px"}}/>
      <div style={{fontSize:11,color:"rgba(255,255,255,0.85)",letterSpacing:3,textTransform:"uppercase"}}>Loading from Supabase…</div>
      <div style={{width:180,height:3,background:"rgba(255,255,255,0.3)",borderRadius:2,overflow:"hidden"}}>
        <div style={{height:"100%",background:"white",borderRadius:2,animation:"loadBar 1.4s ease-in-out infinite"}}/>
      </div>
    </div>}
    <div style={{position:"fixed",left:0,top:0,bottom:0,width:215,background:"#1877F2",borderRight:"1px solid rgba(255,255,255,0.1)",zIndex:10,display:"flex",flexDirection:"column"}}>
      <div style={{padding:"16px 16px 12px",borderBottom:"1px solid rgba(255,255,255,0.15)"}}>
        <img src={LOGO} alt="Ingredientz" style={{width:"100%",height:44,objectFit:"contain",objectPosition:"left center",background:"white",borderRadius:7,padding:"5px 10px"}}/>
        <div style={{fontSize:9,color:"rgba(255,255,255,0.6)",letterSpacing:3,textTransform:"uppercase",marginTop:7}}>Enquiry CRM</div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:9}}>
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:loading?"#F5A623":"#42B72A"}}/>
            <span style={{fontSize:10,color:"rgba(255,255,255,0.7)"}}>{loading?"Loading…":"Supabase Live"}</span>
          </div>
          <button onClick={handleRefresh} style={{background:"transparent",border:"1px solid rgba(255,255,255,0.3)",borderRadius:6,padding:"2px 8px",cursor:"pointer",color:"white",fontSize:11}}>↻</button>
        </div>
      </div>
      <nav style={{padding:"12px 10px",flex:1}}>
        {TABS.map(tab=><button key={tab.id} onClick={()=>setActiveTab(tab.id)} style={{width:"100%",textAlign:"left",background:activeTab===tab.id?"rgba(255,255,255,0.2)":"transparent",border:activeTab===tab.id?"1px solid rgba(255,255,255,0.3)":"1px solid transparent",borderRadius:9,padding:"10px 13px",cursor:"pointer",color:activeTab===tab.id?"white":"rgba(255,255,255,0.75)",fontSize:12,fontWeight:activeTab===tab.id?700:500,marginBottom:3,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <span>{tab.icon} {tab.label}</span>
          {tab.badge>0&&<span style={{background:C.red,color:"white",borderRadius:20,padding:"1px 6px",fontSize:10,fontWeight:700}}>{tab.badge}</span>}
        </button>)}
      </nav>
      <div style={{padding:"10px 14px",borderTop:"1px solid rgba(255,255,255,0.15)"}}>
        {[["Enquiries",enquiries.length,"white"],["Active",enquiries.filter(e=>!["PO Received","Lost","No Response","Out of Scope"].includes(e.stage)).length,"#86efac"],["Overdue",overdueReminderCount,overdueReminderCount>0?C.red:"#86efac"]].map(([l,v,col])=>(
          <div key={l} style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:7}}>
            <span style={{fontSize:10,color:"rgba(255,255,255,0.65)"}}>{l}</span>
            <span style={{fontSize:16,fontWeight:700,color:col}}>{v}</span>
          </div>
        ))}
      </div>
    </div>
    <div style={{marginLeft:215,padding:"24px 28px"}}>
      <div style={{marginBottom:22}}>
        <h1 style={{fontSize:26,fontWeight:700,color:C.ink,margin:0,lineHeight:1}}>{TABS.find(t=>t.id===activeTab)?.label}</h1>
        <div style={{fontSize:11,color:C.muted,marginTop:4}}>{new Date().toLocaleDateString("en-GB",{weekday:"long",day:"numeric",month:"long",year:"numeric"})}</div>
      </div>
      {activeTab==="dashboard"&&<Dashboard enquiries={enquiries} users={users} tasks={tasks} onTaskAdd={addTask} onTaskUpdate={updateTask} onTaskDelete={deleteTask}/>}
      {activeTab==="enquiries"&&<EnquiriesTab enquiries={enquiries} customers={customers} users={users} onSelect={setSelectedEnq} onStageChange={stageChange} onDelete={deleteEnquiry} onAdd={addEnquiry}/>}
      {activeTab==="reminders"&&<RemindersTab enquiries={enquiries} onSelect={e=>{setSelectedEnq(e);setActiveTab("enquiries");}}/>}
      {activeTab==="customers"&&<CustomersTab customers={customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer}/>}
      {activeTab==="users"&&<UsersTab users={users} onAdd={addUser} onUpdate={updateUser} onDelete={deleteUser}/>}
    </div>
    <EnquiryDrawer enq={selectedEnq} onClose={()=>setSelectedEnq(null)} onStageChange={stageChange} onUpdate={updateEnquiry} customers={customers} users={users} quotations={quotations} threads={threads} onSaveQuotation={saveQuotation} onSendQuotationEmail={sendQuotationEmail} onLogEmail={logEmail}/>
    <style>{`
      *{box-sizing:border-box;}
      ::-webkit-scrollbar{width:5px;height:5px;}
      ::-webkit-scrollbar-track{background:#F0F2F5;}
      ::-webkit-scrollbar-thumb{background:#BCC0C4;border-radius:3px;}
      input[type="date"]::-webkit-calendar-picker-indicator{cursor:pointer;opacity:0.7;}
      @keyframes loadBar{0%{width:0%;margin-left:0}50%{width:60%;margin-left:20%}100%{width:0%;margin-left:100%}}
    `}</style>
  </div>;
}
